                      id="royalty-free-confirm"
                      checked={isRoyaltyFreeConfirmed}
                      onChange={(e) => setIsRoyaltyFreeConfirmed(e.target.checked)}
                      className="mt-1 size-4 rounded border-gray-300 accent-[#D4AF37]"
                    />
