              </div>
              <div className="flex items-center gap-2 mt-2 flex-wrap">
                <Badge
                  variant="secondary"
                  className="bg-[#4169E1]/10 text-[#4169E1] border-[#4169E1]/20"
                >
                  {listing.category}
                </Badge>
                {listing.isFeatured && (
                  <Badge className="bg-[#D4AF37]/10 text-[#D4AF37] border-[#D4AF37]/20">
