              </div>
              {/* Rating */}
              {reviewStats.total > 0 && (
                <div className="flex items-center gap-2 mt-2">
                  <div className="flex items-center gap-0.5">
                    {Array.from({ length: 5 }).map((_, i) => (
                      <Star
                        key={i}
                        className={`size-4 ${
                          i < Math.round(reviewStats.averageRating)
                            ? 'text-[#D4AF37] fill-[#D4AF37]'
