              </motion.div>
              {(listing.whatsappNumber || listing.user.whatsappNumber) && (
                <div className="flex-1">
                  <WhatsAppButton
                    whatsappNumber={listing.whatsappNumber || listing.user.whatsappNumber || ''}
                    businessName={listing.name}
                    className="w-full py-3"
                  />
                </div>
              )}
              <motion.div whileTap={{ scale: 0.95 }} className="flex-1">
                <Button
                  variant="outline"
                  onClick={handleShare}
                  className="w-full border-[#4169E1]/30 text-[#4169E1] hover:bg-[#4169E1]/5 py-3"
                >
                  <Share2 className="size-4 mr-2" />
                  Share
                </Button>
              </motion.div>
            </div>
          </GlassCard>
        </div>

        {/* QR Code Section */}
        <GlassCard variant="gold" className="text-center">
          <h2 className="text-lg font-semibold text-gray-800 mb-3 flex items-center justify-center gap-2">
            <QrCode className="size-5 text-[#D4AF37]" />
            Quick Access
          </h2>
          <div className="inline-block p-4 bg-white rounded-2xl shadow-lg mb-3">
            <QRCodeSVG
              value={`${typeof window !== 'undefined' ? window.location.origin : ''}/listing/${listing.slug}`}
              size={160}
              bgColor="#ffffff"
              fgColor="#1a1a1a"
              level="M"
              includeMargin={false}
            />
          </div>
          <p className="text-sm text-gray-500">Scan to visit this page</p>
        </GlassCard>

        {/* Back Button */}
        <div className="pt-2 pb-4">
          <motion.div whileTap={{ scale: 0.95 }}>
            <Button
              variant="ghost"
              onClick={() => navigateTo('explore')}
              className="text-gray-500 hover:text-gray-700"
            >
              <ArrowLeft className="size-4 mr-2" />
              Back to Explore
            </Button>
          </motion.div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Newspaper, Calendar, MapPin, ExternalLink, Clock } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { Skeleton } from '@/components/ui/skeleton'
import { GlassCard } from '@/components/glass-card'
import { OptimizedImage } from '@/components/optimized-image'
import { useAppStore } from '@/lib/store'

interface NewsArticle {
  id: string
  title: string
  content: string | null
  imageUrl: string | null
  source: string | null
  isPublished: boolean
  createdAt: string
  city: {
    id: string
    name: string
    slug: string
  }
}

const PLACEHOLDER_IMG = null // Use Royal Glassmorphism gradient fallback instead of external image

export default function NewsView() {
  // Use individual selectors to prevent re-rendering on unrelated store changes
  const selectedCity = useAppStore((s) => s.selectedCity)
  const [articles, setArticles] = useState<NewsArticle[]>([])
  const [loading, setLoading] = useState(true)
  const [cities, setCities] = useState<Array<{ id: string; name: string; slug: string }>>([])
  const [cityId, setCityId] = useState('')

  // Fetch cities for filter
  useEffect(() => {
    fetch('/api/cities')
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setCities(data)
          const matched = data.find((c: { slug: string }) => c.slug === selectedCity)
          setCityId(matched?.id || '')
        }
      })
      .catch(() => {})
  }, [selectedCity])

  // Fetch news
  useEffect(() => {
    setLoading(true)
    const params = new URLSearchParams()
    if (cityId) params.set('cityId', cityId)

    fetch(`/api/news?${params}`)
      .then((res) => res.json())
      .then((data) => {
        setArticles(Array.isArray(data) ? data : [])
      })
      .catch(() => setArticles([]))
      .finally(() => setLoading(false))
  }, [cityId])

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })
  }

  const getTimeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime()
    const mins = Math.floor(diff / 60000)
    if (mins < 60) return `${mins}m ago`
    const hours = Math.floor(mins / 60)
    if (hours < 24) return `${hours}h ago`
    const days = Math.floor(hours / 24)
    if (days < 7) return `${days}d ago`
    return formatDate(dateStr)
  }

  // Skeleton
  const SkeletonList = () => (
    <div className="space-y-4">
      {Array.from({ length: 4 }).map((_, i) => (
        <div key={i} className="flex gap-4 p-4 rounded-2xl bg-white border border-gray-100">
          <Skeleton className="w-28 h-28 rounded-xl shrink-0" />
          <div className="flex-1 space-y-2">
            <Skeleton className="h-5 w-3/4" />
            <Skeleton className="h-4 w-full" />
            <Skeleton className="h-4 w-1/2" />
          </div>
        </div>
      ))}
    </div>
  )

  return (
    <div className="max-w-4xl mx-auto px-4 py-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-[#4169E1]/10 flex items-center justify-center">
            <Newspaper className="size-5 text-[#4169E1]" />
          </div>
          <div>
            <h1 className="text-xl sm:text-2xl font-bold text-gray-900">Local News</h1>
            <p className="text-sm text-gray-500">Stay updated with your city</p>
          </div>
        </div>
        {cities.length > 0 && (
          <div className="flex gap-2 overflow-x-auto">
            <motion.button
              whileTap={{ scale: 0.95 }}
              onClick={() => setCityId('')}
              className={`px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${
                !cityId
                  ? 'bg-gradient-to-r from-[#4169E1] to-[#3155C1] text-white shadow-md'
                  : 'bg-white/50 text-gray-600 border border-white/40'
              }`}
            >
              All Cities
            </motion.button>
            {cities.map((city) => (
              <motion.button
                key={city.id}
                whileTap={{ scale: 0.95 }}
                onClick={() => setCityId(city.id)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${
                  cityId === city.id
                    ? 'bg-gradient-to-r from-[#4169E1] to-[#3155C1] text-white shadow-md'
                    : 'bg-white/50 text-gray-600 border border-white/40'
                }`}
              >
                {city.name}
              </motion.button>
            ))}
          </div>
        )}
      </div>

      {/* Articles */}
      {loading ? (
        <SkeletonList />
      ) : articles.length === 0 ? (
        <GlassCard className="text-center py-12">
          <Newspaper className="size-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500 font-medium">No news articles yet</p>
          <p className="text-sm text-gray-400 mt-1">
            Check back later for local updates
          </p>
        </GlassCard>
      ) : (
        <div className="space-y-4">
          {/* Featured article (first one) */}
          {articles[0] && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4 }}
            >
              <GlassCard variant="gold" className="!p-0 overflow-hidden">
                <div className="relative max-h-[250px] h-48 sm:h-[250px] overflow-hidden">
                  {articles[0].imageUrl ? (
                    <OptimizedImage
                      src={articles[0].imageUrl}
                      alt={articles[0].title}
                      fill
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <div className="absolute inset-0 bg-gradient-to-br from-[#4169E1] to-[#D4AF37] flex items-center justify-center">
                      <Newspaper className="w-12 h-12 text-white/40" />
                    </div>
                  )}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent" />
                  <div className="absolute bottom-0 left-0 right-0 p-4 sm:p-6">
                    <Badge className="bg-[#D4AF37] text-white border-none mb-2 text-xs">
                      Featured
                    </Badge>
                    <h2 className="text-lg sm:text-xl font-bold text-white mb-1 line-clamp-2">
                      {articles[0].title}
                    </h2>
                    <div className="flex items-center gap-3 text-xs text-white/80">
                      <span className="flex items-center gap-1">
                        <Calendar className="size-3" />
                        {formatDate(articles[0].createdAt)}
