            ))}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { ArrowLeft, ShieldCheck, Crown } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { useAppStore } from '@/lib/store'
import { useAuth } from '@/lib/auth-context'
import { toast } from 'sonner'
import IndividualProfilePage from '@/components/profile/individual-profile-page'
import LeaderProfilePage from '@/components/profile/leader-profile-page'

// ─── Types ─────────────────────────────────────────────────
interface ProfileData {
  id: string
  userId: string
  bio: string
  avatarUrl: string | null
  coverImageUrl: string | null
  isPublicFigure: boolean
  publicFigureCategory: string | null
  isVerified: boolean
  followersCount: number
  followingCount: number
  user: {
    id: string
    fullName: string
    avatarUrl: string | null
    createdAt: string
  }
}

const CATEGORY_LABELS: Record<string, string> = {
  POLITICIAN: 'నాయకుడు',
  INFLUENCER: 'Influencer',
  GOVT_OFFICIAL: 'ప్రభుత్వోద్యోగి',
  CELEBRITY: 'Celebrity',
}

// ─── Component ──────────────────────────────────────────────
export default function ProfileView() {
  const selectedProfileUserId = useAppStore((s) => s.selectedProfileUserId)
  const navigateTo = useAppStore((s) => s.navigateTo)
  const currentUser = useAppStore((s) => s.currentUser)
  const profileType = useAppStore((s) => s.profileType)
  const { isAuthenticated, user } = useAuth()

  const isOwnProfile = !selectedProfileUserId || (currentUser && selectedProfileUserId === currentUser.id)
  const profileUserId = isOwnProfile ? currentUser?.id : selectedProfileUserId

  const [profile, setProfile] = useState<ProfileData | null>(null)
  const [loading, setLoading] = useState(true)

  // Fetch profile
  const fetchProfile = useCallback(async () => {
    if (!profileUserId) return
    setLoading(true)
    try {
      const res = await fetch(`/api/social/profiles?userId=${profileUserId}`)
      if (res.ok) {
        const data = await res.json()
        const profileData = data.profile || data
        setProfile(profileData)
      }
    } catch {
      toast.error('Failed to load profile')
    } finally {
      setLoading(false)
    }
  }, [profileUserId])

  useEffect(() => {
    fetchProfile()
  }, [fetchProfile])

  // ─── Loading State ───────────────────────────────────────
  if (loading) {
    return (
      <div className="space-y-4 animate-pulse">
        <div className="h-40 md:h-52 rounded-2xl bg-gray-200" />
        <div className="px-4 -mt-12">
          <div className="w-24 h-24 rounded-full bg-gray-300" />
        </div>
        <div className="px-4 space-y-2">
          <div className="h-5 w-40 bg-gray-200 rounded" />
          <div className="h-3 w-64 bg-gray-100 rounded" />
          <div className="h-3 w-48 bg-gray-100 rounded" />
        </div>
      </div>
    )
  }

  // ─── Determine Profile Type ──────────────────────────────
  // Priority:
  // 1. Explicit profileType from store (set by navigation)
  // 2. Profile data: POLITICIAN / GOVT_OFFICIAL → Leader, else Individual
  // 3. Default: Individual
  const isLeaderProfile =
    profileType === 'leader' ||
    profile?.publicFigureCategory === 'POLITICIAN' ||
    profile?.publicFigureCategory === 'GOVT_OFFICIAL'

  // ─── Render Leader Profile ───────────────────────────────
  if (isLeaderProfile) {
    return (
      <LeaderProfilePage
        profileData={
          profile
            ? {
                id: profile.id,
                fullName: profile.user.fullName,
                designation: CATEGORY_LABELS[profile.publicFigureCategory || ''] || 'Community Leader',
                party: 'Public Service',
                partyColor: '#D4AF37',
                constituency: 'Choutuppal, Yadadri Bhuvanagiri',
                avatarUrl: profile.avatarUrl || profile.user.avatarUrl,
                coverImageUrl: profile.coverImageUrl,
                isVerified: profile.isVerified,
                bio: profile.bio || '',
                followersCount: profile.followersCount,
                followingCount: profile.followingCount,
                vision: [
                  'Quality education for every child',
                  'Modern healthcare facilities in all villages',
                  'Employment opportunities through development',
                  'Complete road connectivity to all areas',
                ],
                achievements: [],
                events: [],
                office: {
                  address: 'Choutuppal, Yadadri Bhuvanagiri',
                  paContact: '+91 00000 00000',
                  officeHours: 'Mon-Sat: 10:00 AM - 5:00 PM',
                  email: 'contact@example.com',
                },
              }
            : undefined
        }
      />
    )
  }

  // ─── Render Individual Profile ───────────────────────────
  return (
    <IndividualProfilePage
      profileData={
        profile
          ? {
              id: profile.id,
              fullName: profile.user.fullName,
              profession: profile.publicFigureCategory === 'INFLUENCER'
                ? 'Influencer'
                : profile.publicFigureCategory === 'CELEBRITY'
                  ? 'Celebrity'
                  : 'Professional',
              city: 'Choutuppal',
              avatarUrl: profile.avatarUrl || profile.user.avatarUrl,
              coverImageUrl: profile.coverImageUrl,
              isVerified: profile.isVerified,
              bio: profile.bio || '',
              followersCount: profile.followersCount,
              followingCount: profile.followingCount,
              postsCount: 0,
              skills: [],
              services: [],
              reviews: [],
            }
          : undefined
      }
    />
  )
}

'use client'

import { createContext, useContext, useEffect, useState, useCallback, useRef } from 'react'

interface PWAInstallContextType {
  installPrompt: BeforeInstallPromptEvent | null
  isInstallable: boolean
  isInstalled: boolean
  isIOS: boolean
  isMobile: boolean
  triggerInstall: () => Promise<boolean>
  dismissInstall: () => void
  showInstallPopup: boolean
  wasDismissed: boolean
}

interface BeforeInstallPromptEvent extends Event {
  prompt(): Promise<void>
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>
}

const PWAInstallContext = createContext<PWAInstallContextType>({
  installPrompt: null,
  isInstallable: false,
  isInstalled: false,
  isIOS: false,
  isMobile: false,
  triggerInstall: async () => false,
  dismissInstall: () => {},
  showInstallPopup: false,
  wasDismissed: false,
})

export function usePWAInstall() {
  return useContext(PWAInstallContext)
}

const DISMISS_KEY = 'pwa-install-dismissed'
const DISMISS_DURATION = 7 * 24 * 60 * 60 * 1000 // 7 days

function checkWasDismissed(): boolean {
  if (typeof window === 'undefined') return false
  try {
    const dismissedAt = localStorage.getItem(DISMISS_KEY)
    if (dismissedAt) {
      const elapsed = Date.now() - parseInt(dismissedAt, 10)
      if (elapsed < DISMISS_DURATION) return true
      localStorage.removeItem(DISMISS_KEY)
    }
  } catch { /* ignore */ }
  return false
}

function checkIsStandalone(): boolean {
  if (typeof window === 'undefined') return false
  return (
    window.matchMedia('(display-mode: standalone)').matches ||
    // @ts-expect-error - standalone is iOS-specific
    navigator.standalone === true
  )
}

function detectIOS(): boolean {
  if (typeof navigator === 'undefined') return false
  return (
    /iPad|iPhone|iPod/.test(navigator.userAgent) &&
    // @ts-expect-error - standalone is iOS-specific
    !navigator.standalone
  )
}

function detectMobile(): boolean {
  if (typeof window === 'undefined') return false
  return /Android|iPhone|iPad|iPod|Opera Mini|IEMobile|WPDesktop/i.test(navigator.userAgent)
}

export function PWAInstallProvider({ children }: { children: React.ReactNode }) {
  const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null)
  const [isInstalled, setIsInstalled] = useState(false)
  const [wasDismissed, setWasDismissed] = useState(false)
  const promptRef = useRef<BeforeInstallPromptEvent | null>(null)

  useEffect(() => {
    setIsInstalled(checkIsStandalone())
    setWasDismissed(checkWasDismissed())
  }, [])

  const isIOS = detectIOS()
  const isMobile = detectMobile()


  // Keep ref in sync
  useEffect(() => {
    promptRef.current = installPrompt
  }, [installPrompt])

  // Listen for display-mode changes (when app gets installed at runtime)
  useEffect(() => {
    if (typeof window === 'undefined') return
    const mq = window.matchMedia('(display-mode: standalone)')
    const handler = (e: MediaQueryListEvent) => { if (e.matches) setIsInstalled(true) }
    mq.addEventListener('change', handler)
    return () => mq.removeEventListener('change', handler)
  }, [])

  // Capture beforeinstallprompt
  useEffect(() => {
    if (typeof window === 'undefined') return
    const handler = (e: Event) => {
      e.preventDefault()
      setInstallPrompt(e as BeforeInstallPromptEvent)
    }
    window.addEventListener('beforeinstallprompt', handler)
    return () => window.removeEventListener('beforeinstallprompt', handler)
  }, [])

  // Listen for appinstalled
  useEffect(() => {
    if (typeof window === 'undefined') return
    const handler = () => { setIsInstalled(true); setInstallPrompt(null) }
    window.addEventListener('appinstalled', handler)
    return () => window.removeEventListener('appinstalled', handler)
  }, [])

  // Register service worker
  useEffect(() => {
    if (typeof window === 'undefined' || !('serviceWorker' in navigator)) return
    navigator.serviceWorker.register('/sw.js').catch(() => {})
  }, [])

  const triggerInstall = useCallback(async (): Promise<boolean> => {
    const prompt = promptRef.current
    if (!prompt) return false
    try {
      await prompt.prompt()
      const { outcome } = await prompt.userChoice
      if (outcome === 'accepted') { setIsInstalled(true); setInstallPrompt(null); return true }
      return false
    } catch { return false }
  }, [])

  const dismissInstall = useCallback(() => {
    setWasDismissed(true)
    try { localStorage.setItem(DISMISS_KEY, Date.now().toString()) } catch { /* ignore */ }
  }, [])

  const isInstallable = !!installPrompt && !isInstalled
  const showInstallPopup = isInstallable && !wasDismissed && isMobile

  return (
    <PWAInstallContext.Provider value={{
      installPrompt, isInstallable, isInstalled, isIOS, isMobile,
      triggerInstall, dismissInstall, showInstallPopup, wasDismissed,
    }}>
      {children}
    </PWAInstallContext.Provider>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { motion } from 'framer-motion'
import {
  ArrowLeft, Search, Star, MapPin, BadgeCheck, Phone,
  Store, X,
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Skeleton } from '@/components/ui/skeleton'
import { GlassCard } from '@/components/glass-card'
import { OptimizedImage } from '@/components/optimized-image'
import { useAppStore } from '@/lib/store'

interface SearchResult {
  id: string
  slug: string
  name: string
  category: string
  description: string | null
  images: string | null
  whatsappNumber: string | null
  address: string | null
  isPremium: boolean
  isFeatured: boolean
  viewsCount: number
  user: {
    id: string
    fullName: string
    avatarUrl: string | null
  }
  city: {
    id: string
    name: string
    slug: string
  }
  _count: {
    reviews: number
    leads: number
  }
}

const PLACEHOLDER_IMG = 'https://placehold.co/400x250/4169E1/ffffff?text=Business'

export default function SearchView() {
  // Use individual selectors to prevent re-rendering on unrelated store changes
  const searchQuery = useAppStore((s) => s.searchQuery)
  const setSearchQuery = useAppStore((s) => s.setSearchQuery)
  const selectedCity = useAppStore((s) => s.selectedCity)
  const setSelectedListing = useAppStore((s) => s.setSelectedListing)
  const navigateTo = useAppStore((s) => s.navigateTo)
  const setShowLeadForm = useAppStore((s) => s.setShowLeadForm)
  const setLeadFormListingId = useAppStore((s) => s.setLeadFormListingId)
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [localQuery, setLocalQuery] = useState(searchQuery)
  const [cities, setCities] = useState<Array<{ id: string; name: string; slug: string }>>([])
  const [cityId, setCityId] = useState('')

  // Fetch cities
  useEffect(() => {
    fetch('/api/cities')
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setCities(data)
          const matched = data.find((c) => c.slug === selectedCity)
          setCityId(matched?.id || '')
        }
      })
      .catch(() => {})
  }, [selectedCity])

  // Search listings
  const performSearch = useCallback(async (query: string) => {
    if (!query.trim()) {
      setResults([])
      return
    }

    setLoading(true)
    try {
      const params = new URLSearchParams()
      params.set('search', query)
      params.set('limit', '20')
      if (cityId) params.set('cityId', cityId)

      const res = await fetch(`/api/listings?${params}`)
      if (res.ok) {
        const data = await res.json()
        setResults(data.listings || [])
      }
    } catch {
      setResults([])
    } finally {
      setLoading(false)
    }
  }, [cityId])

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (localQuery.trim()) {
        performSearch(localQuery)
      } else {
        setResults([])
      }
    }, 300)

    return () => clearTimeout(timer)
  }, [localQuery, performSearch])

  // Trigger initial search if query exists (or when searchQuery changes from external source)
  useEffect(() => {
    if (searchQuery) {
      setLocalQuery(searchQuery)
      performSearch(searchQuery)
    }
  }, [searchQuery])

  const handleCardClick = (slug: string) => {
    setSelectedListing(slug)
    navigateTo('listing')
  }

  const handleGetQuote = (e: React.MouseEvent, listingId: string) => {
    e.stopPropagation()
    setLeadFormListingId(listingId)
    setShowLeadForm(true)
  }

  const handleClearSearch = () => {
    setLocalQuery('')
    setSearchQuery('')
    setResults([])
  }

  // Skeleton
  const SkeletonGrid = () => (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
      {Array.from({ length: 6 }).map((_, i) => (
        <div key={i} className="rounded-2xl overflow-hidden">
          <Skeleton className="w-full h-36 rounded-t-2xl" />
          <div className="p-4 space-y-2 bg-white/40 backdrop-blur-xl">
            <Skeleton className="h-5 w-3/4" />
            <Skeleton className="h-4 w-1/2" />
          </div>
        </div>
      ))}
    </div>
  )

  return (
    <div className="max-w-6xl mx-auto px-4 py-6 space-y-6">
      {/* Search bar */}
      <GlassCard className="!p-4">
        <div className="flex items-center gap-3">
          <motion.div whileTap={{ scale: 0.95 }}>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => navigateTo('home')}
              className="shrink-0 hover:bg-white/50"
            >
              <ArrowLeft className="size-5" />
            </Button>
          </motion.div>
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-gray-400" />
            <Input
              placeholder="Search businesses, services, categories..."
              value={localQuery}
              onChange={(e) => {
                setLocalQuery(e.target.value)
                setSearchQuery(e.target.value)
              }}
              autoFocus
              className="pl-10 pr-10 bg-white/50 border-white/40 focus:border-[#D4AF37]/50 focus:ring-[#D4AF37]/20 text-base"
            />
            {localQuery && (
              <motion.button
                whileTap={{ scale: 0.9 }}
                onClick={handleClearSearch}
                className="absolute right-3 top-1/2 -translate-y-1/2"
              >
                <X className="size-4 text-gray-400 hover:text-gray-600" />
              </motion.button>
            )}
          </div>
        </div>
      </GlassCard>

      {/* Results info */}
      {localQuery.trim() && (
        <div className="flex items-center justify-between">
          <p className="text-sm text-gray-500">
            {loading ? (
              'Searching...'
            ) : (
              <>
                <span className="font-medium text-gray-700">{results.length}</span> result{results.length !== 1 ? 's' : ''} for &ldquo;
                <span className="font-medium text-[#4169E1]">{localQuery}</span>&rdquo;
              </>
            )}
          </p>
        </div>
      )}

      {/* Results */}
      {!localQuery.trim() ? (
        <GlassCard className="text-center py-16">
          <Search className="size-16 text-gray-200 mx-auto mb-4" />
          <p className="text-gray-500 font-medium text-lg">Search Choutuppal</p>
          <p className="text-sm text-gray-400 mt-1 max-w-sm mx-auto">
            Find businesses, services, restaurants, and more in your city
          </p>
          {/* Popular categories */}
          <div className="flex flex-wrap gap-2 justify-center mt-6">
            {['Tiffin', 'Medical', 'Salon', 'Plumber', 'Education', 'Electronics'].map((cat) => (
              <motion.button
                key={cat}
                whileTap={{ scale: 0.95 }}
                onClick={() => {
                  setLocalQuery(cat)
                  setSearchQuery(cat)
                }}
                className="px-4 py-2 rounded-xl bg-white/50 border border-white/40 text-sm text-gray-600 hover:bg-white/70 transition-colors"
              >
                {cat}
              </motion.button>
            ))}
          </div>
        </GlassCard>
      ) : loading ? (
        <SkeletonGrid />
      ) : results.length === 0 ? (
        <GlassCard className="text-center py-12">
          <Store className="size-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500 font-medium">No results found</p>
          <p className="text-sm text-gray-400 mt-1">
            Try a different search term or browse categories
          </p>
        </GlassCard>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {results.map((listing, idx) => {
            const images = listing.images
              ? (() => {
                  try {
                    const parsed = JSON.parse(listing.images)
                    return Array.isArray(parsed) ? parsed : []
                  } catch {
                    return []
                  }
                })()
              : []
            const coverImg = images[0] || PLACEHOLDER_IMG

            return (
              <motion.div
                key={listing.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.05, duration: 0.3 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => handleCardClick(listing.slug)}
                className="cursor-pointer"
              >
                <GlassCard
                  variant={listing.isPremium ? 'gold' : 'default'}
                  className="!p-0 overflow-hidden hover:shadow-xl transition-shadow"
                >
                  {/* Image */}
                  <div className="relative h-36 overflow-hidden">
                    <OptimizedImage
                      src={coverImg}
                      alt={listing.name}
                      fill
                      className="w-full h-full object-cover transition-transform hover:scale-105 duration-300"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/30 to-transparent" />
                    {listing.isPremium && (
                      <Badge className="absolute top-2 right-2 bg-[#D4AF37] text-white border-none text-xs">
                        <BadgeCheck className="size-3 mr-0.5" />
                        Premium
                      </Badge>
                    )}
                  </div>

                  {/* Content */}
                  <div className="p-4 space-y-2">
                    <h3 className="font-semibold text-gray-900 line-clamp-1">
                      {listing.name}
                    </h3>
                    <div className="flex items-center gap-2 flex-wrap">
                      <Badge
                        variant="secondary"
                        className="bg-[#4169E1]/10 text-[#4169E1] border-[#4169E1]/20 text-xs"
                      >
                        {listing.category}
                      </Badge>
                      {listing._count.reviews > 0 && (
                        <div className="flex items-center gap-1 text-xs text-gray-500">
                          <Star className="size-3 text-[#D4AF37] fill-[#D4AF37]" />
                          {listing._count.reviews}
                        </div>
                      )}
                    </div>
                    {listing.address && (
                      <p className="text-xs text-gray-500 line-clamp-1 flex items-center gap-1">
                        <MapPin className="size-3 shrink-0" />
                        {listing.address}
                      </p>
                    )}
                    <div className="pt-1">
                      <motion.div whileTap={{ scale: 0.95 }}>
                        <Button
                          size="sm"
                          onClick={(e) => handleGetQuote(e, listing.id)}
                          className="bg-gradient-to-r from-[#D4AF37] to-[#B8962E] text-white text-xs h-8"
                        >
                          <Phone className="size-3 mr-1" />
                          Get Quote
                        </Button>
                      </motion.div>
                    </div>
                  </div>
                </GlassCard>
              </motion.div>
            )
          })}
        </div>
      )}
    </div>
  )
}

